import { _decorator, Component, Node } from 'cc';
const { ccclass, property } = _decorator;

@ccclass('parameters')
export class parameters {

    private static readonly CELL_WIDTH = 140;
    private static readonly CELL_HEIGHT = 110;
    private static readonly GRID_OFFSET_Y = 180;

    // private symbols: Prefab[] = [];
    // private gridOffsetX: number = 0;

    public n: number;
    public m: number;
    public x: number;
    public y: number;

    public getN(): number { return this.n; };
    public getM() { return this.m; };
    public getX() { return this.x; };
    public getY() { return this.y; };

    public setN(n: number) { this.n = n; };
    public setM(m) { this.m = m; };
    public setX(x) { this.x = x; };
    public setY(y) { this.y = y; };
        
    
}


